pub fn executor(
    protocol_config: &ProtocolConfig,
    silent: bool,
) -> SuiResult<Arc<dyn Executor + Send + Sync>> {
    let version = protocol_config.execution_version_as_option().unwrap_or(0);
    Ok(match version {
        0 => Arc::new(v0::Executor::new(protocol_config, silent)?),

        1 => Arc::new(v1::Executor::new(protocol_config, silent)?),

        2 => Arc::new(v2::Executor::new(protocol_config, silent)?),

        3 => Arc::new(v3::Executor::new(protocol_config, silent)?),

        4 => Arc::new(latest::Executor::new(protocol_config, silent)?),

        v => panic!("Unsupported execution version {v}"),
    })
}

pub fn verifier<'m>(
    protocol_config: &ProtocolConfig,
    signing_limits: Option<(usize, usize, usize)>,
    metrics: &'m Arc<BytecodeVerifierMetrics>,
) -> Box<dyn Verifier + 'm> {
    let version = protocol_config.execution_version_as_option().unwrap_or(0);
    let config = protocol_config.verifier_config(signing_limits);
    match version {
        0 => Box::new(v0::Verifier::new(config, metrics)),
        1 => Box::new(v1::Verifier::new(config, metrics)),
        2 => Box::new(v2::Verifier::new(config, metrics)),
        3 => Box::new(v3::Verifier::new(config, metrics)),
        4 => Box::new(latest::Verifier::new(config, metrics)),
        v => panic!("Unsupported execution version {v}"),
    }
}

pub fn collect_unification_information_for_signing(
    protocol_config: &ProtocolConfig,
    pt: &ProgrammableTransaction,
    package_store: &dyn BackingPackageStore,
) -> SuiResult<(
    BTreeSet<AccountAddress>,
    BTreeMap<AccountAddress, AccountAddress>,
)> {
    if !protocol_config.enable_unified_linkage() {
        return Ok((BTreeSet::new(), BTreeMap::new()));
    }

    let version = protocol_config.execution_version_as_option().unwrap_or(0);
    match version {
        0 => Ok((BTreeSet::new(), BTreeMap::new())),
        1 => Ok((BTreeSet::new(), BTreeMap::new())),
        2 => Ok((BTreeSet::new(), BTreeMap::new())),
        3 => Ok((BTreeSet::new(), BTreeMap::new())),
        4 => {
            latest::collect_unification_information_for_signing(protocol_config, pt, package_store)
        }
        v => panic!("Unsupported execution version {v}"),
    }
}
